525→pub async fn explore_function(
526→    frontend: &mut Frontend,
527→    analysis: &FunctionAnalysis,
528→    config: &ExploreConfig,
529→) -> Result<ObservationOutput, ExploreError> {
530→    let instrument_response = frontend
531→        .send(ProtoCommand::Instrument {
532→            file: config.file.clone(),
533→            function: analysis.name.clone(),
534→            mocks: config.mocks.clone(),
535→            project_root: config.project_root.clone(),
536→        })
537→        .await?;
538→
539→    let instrumentable_line_count = match instrument_response.result {
540→        ResponseResult::Instrument { instrumented, instrumentable_line_count, .. } => {
541→            if !instrumented {
542→                return Err(ExploreError::UnexpectedResponse(
543→                    "instrumentation returned instrumented=false".to_string(),
544→                ));
545→            }
546→            instrumentable_line_count
547→        }
548→        ResponseResult::Error { code, message, .. } => {
549→            return Err(ExploreError::UnexpectedResponse(format!(
550→                "instrument error ({code:?}): {message}"
551→            )));
552→        }
553→        other => {
554→            return Err(ExploreError::UnexpectedResponse(format!(
555→                "expected Instrument response, got {other:?}"
556→            )));
557→        }
558→    };
559→
560→    let mut rng = match config.seed {
561→        Some(seed) => StdRng::seed_from_u64(seed),
562→        None => StdRng::from_os_rng(),
563→    };
564→
565→    // --- Setup lifecycle ---
566→    let has_setup =
567→        config.setup_file.is_some() && frontend_supports(&config.capabilities, "setup");
568→    let per_function_setup = has_setup && config.setup_level == SetupLevel::Function;
569→    let per_execution_setup = has_setup && config.setup_level == SetupLevel::Execution;
570→
571→    let mut setup_context: Option<SetupContextStack> = None;
572→
573→    if per_function_setup
574→        && let Some(ref setup_file) = config.setup_file
575→    {
576→        setup_context =
577→            send_setup(frontend, setup_file, &analysis.name, config.setup_level, config.project_root.clone()).await?;
578→    }
579→
580→    // --- Generator prefetch ---
581→    let has_generators = config
582→        .value_sources
583→        .iter()
584→        .any(|s| matches!(s, ValueSource::CustomGenerator { .. }));
585→    let use_generators = has_generators && frontend_supports(&config.capabilities, "generate");
586→
587→    let mut prefetched = if use_generators {
588→        prefetch_custom_values(&config.value_sources, frontend, config.max_iterations as usize)
589→            .await
590→            .unwrap_or_else(|e| {
591→                log::debug!("prefetch failed, falling back to built-in: {e}");
592→                PrefetchedValues::new()
593→            })
594→    } else {
595→        PrefetchedValues::new()
596→    };
597→
598→    let mut seen_paths: HashSet<u64> = HashSet::new();
599→    let mut all_lines: HashSet<u32> = HashSet::new();
600→    let mut new_path_executions: Vec<ExecutionSummary> = Vec::new();
601→    let mut raw_results: Vec<(Vec<serde_json::Value>, ExecuteResult)> = Vec::new();
602→    let mut iterations: u32 = 0;
603→    let mut path_counts: HashMap<u64, u32> = HashMap::new();
604→    let mut seen_branch_ids: HashSet<u32> = HashSet::new();
605→    let mut discoveries: Vec<(u32, DiscoveryMethod)> = Vec::new();
606→
607→    // --- Float probe phase ---
608→    // Probes consume from the iteration budget, contributing to seen_paths and raw_results.
609→    let float_indices = crate::float_probe::float_param_indices(&analysis.params);
610→    let mut float_probe_results: Vec<crate::float_probe::FloatProbeResult> = Vec::new();
611→    let probe_budget = float_indices.len() * crate::float_probe::PROBE_COUNT * 2;
612→    if !float_indices.is_empty() && probe_budget < config.max_iterations as usize {
613→        for &idx in &float_indices {
614→            let pairs = crate::float_probe::generate_probe_pairs(
615→                &analysis.params,
616→                idx,
617→                crate::float_probe::PROBE_COUNT,
618→                &mut rng,
619→            );
620→            let mut agreements = 0usize;
621→            let mut total_probes = 0usize;
622→            let mut divergent_values = Vec::new();
623→
624→            for (float_inputs, floor_inputs) in pairs {
625→                let float_resp = frontend
626→                    .send(ProtoCommand::Execute {
627→                        function: analysis.name.clone(),
628→                        inputs: float_inputs.clone(),
629→                        mocks: config.mocks.clone(),
630→                        setup_context: setup_context.clone(),
631→                    })
632→                    .await?;
633→
634→                let floor_resp = frontend
635→                    .send(ProtoCommand::Execute {
636→                        function: analysis.name.clone(),
637→                        inputs: floor_inputs,
638→                        mocks: config.mocks.clone(),
639→                        setup_context: setup_context.clone(),
640→                    })
641→                    .await?;
642→
643→                if let (
644→                    ResponseResult::Execute(float_result),
645→                    ResponseResult::Execute(floor_result),
646→                ) = (&float_resp.result, &floor_resp.result) {
647→                    total_probes += 1;
648→
649→                    let fhash = path_hash(float_result, &config.loop_buckets);
650→                    let flhash = path_hash(floor_result, &config.loop_buckets);
651→                    seen_paths.insert(fhash);
652→                    seen_paths.insert(flhash);
653→                    for &line in &float_result.lines_executed {
654→                        all_lines.insert(line);
655→                    }
656→                    for &line in &floor_result.lines_executed {
657→                        all_lines.insert(line);
658→                    }
659→
660→                    if crate::float_probe::executions_agree(float_result, floor_result) {
661→                        agreements += 1;
662→                    } else if let Some(v) = float_inputs.get(idx).and_then(|v| v.as_f64()) {
663→                        divergent_values.push(v);
664→                    }
665→
666→                    raw_results.push((float_inputs.clone(), (**float_result).clone()));
667→                }
668→            }
669→
670→            let classification = crate::float_probe::classify(
671→                agreements,
672→                total_probes,
673→                crate::float_probe::AGREEMENT_THRESHOLD,
674→            );
675→            float_probe_results.push(crate::float_probe::FloatProbeResult {
676→                param_index: idx,
677→                param_name: analysis.params[idx].name.clone(),
678→                classification,
679→                agreements,
680→                total_probes,
681→                divergent_values,
682→            });
683→        }
684→    }
685→
686→    let float_bias = crate::float_probe::build_bias_map(&float_probe_results);
687→    let has_integer_treating = float_bias
688→        .values()
689→        .any(|c| *c == crate::float_probe::FloatClassification::IntegerTreating);
690→
691→    // --- User-provided candidate inputs (highest priority, no budget cap) ---
692→    let mut user_iter = config.user_seeds.iter().cloned().peekable();
693→
694→    // --- Literal-derived seed inputs ---
695→    // Execute extracted literals first to cover magic-value branches before random exploration.
696→    let literal_candidates = literals_to_candidate_inputs(&analysis.params, &analysis.literals);
697→    let literal_budget = literal_candidates
698→        .len()
699→        .min(config.max_iterations as usize / 2);
700→    let mut literal_iter = literal_candidates.into_iter().take(literal_budget).peekable();
701→
702→    // --- Candidate inputs (from --inputs or .shatter/ config) ---
703→    // Priority above pool seeds, below literal seeds.
704→    let candidate_budget = config
705→        .candidate_inputs
706→        .len()
707→        .min(config.max_iterations as usize / 3);
708→    let mut candidate_iter = config.candidate_inputs.iter().take(candidate_budget).cloned().peekable();
709→
710→    // --- Pool-derived seed inputs ---
711→    // Cross-function interesting values, injected after literals but before random generation.
712→    let pool_budget = config
713→        .pool_seeds
714→        .len()
715→        .min(config.max_iterations as usize / 4);
716→    let mut pool_iter = config.pool_seeds.iter().take(pool_budget).cloned().peekable();
717→
718→    let explore_start = Instant::now();
719→
720→    for _ in 0..config.max_iterations {
721→        if let Some(timeout) = config.timeout_explore
722→            && explore_start.elapsed() >= timeout
723→        {
724→            break;
725→        }
726→
727→        iterations += 1;
728→
729→        // --- Per-execution setup ---
730→        if per_execution_setup
731→            && let Some(ref setup_file) = config.setup_file
732→        {
733→            setup_context =
734→                send_setup(frontend, setup_file, &analysis.name, config.setup_level, config.project_root.clone()).await?;
735→        }
736→
737→        // --- Input generation ---
738→        // Priority: user seeds → literals → candidate inputs → pool seeds → custom generators → random.
739→        let inputs = if let Some(user_inputs) = user_iter.next() {
740→            user_inputs
741→        } else if let Some(lit_inputs) = literal_iter.next() {
742→            lit_inputs
743→        } else if let Some(cand_inputs) = candidate_iter.next() {
744→            cand_inputs
745→        } else if let Some(pool_inputs) = pool_iter.next() {
746→            pool_inputs
747→        } else if use_generators {
748→            generate_inputs_with_custom(
749→                &analysis.params,
750→                &config.value_sources,
751→                &mut prefetched,
752→                &mut rng,
753→                Some(&config.capabilities),
754→            )
755→        } else if has_integer_treating {
756→            crate::input_gen::generate_random_inputs_with_float_bias(
757→                &analysis.params,
758→                &float_bias,
759→                &mut rng,
760→                None,
761→            )
762→        } else {
763→            generate_random_inputs(&analysis.params, &mut rng, None)
764→        };
765→
766→        let response = frontend
767→            .send(ProtoCommand::Execute {
768→                function: analysis.name.clone(),
769→                inputs: inputs.clone(),
770→                mocks: config.mocks.clone(),
771→                setup_context: setup_context.clone(),
772→            })
773→            .await?;
774→
775→        let exec_result = match response.result {
776→            ResponseResult::Execute(result) => *result,
777→            ResponseResult::Error { code, message, .. } => {
778→                return Err(ExploreError::UnexpectedResponse(format!(
779→                    "execute error ({code:?}): {message}"
780→                )));
781→            }
782→            other => {
783→                return Err(ExploreError::UnexpectedResponse(format!("{other:?}")));
784→            }
785→        };
786→
787→        // --- Per-execution teardown ---
788→        if per_execution_setup && frontend_supports(&config.capabilities, "teardown") {
789→            send_teardown(frontend, &analysis.name, config.setup_level).await?;
790→        }
791→
792→        for &line in &exec_result.lines_executed {
793→            all_lines.insert(line);
794→        }
795→
796→        let hash = path_hash(&exec_result, &config.loop_buckets);
797→        *path_counts.entry(hash).or_insert(0) += 1;
798→        let is_new = seen_paths.insert(hash);
799→
800→        // Track per-branch discovery attribution.
801→        for decision in &exec_result.branch_path {
802→            if seen_branch_ids.insert(decision.branch_id) {
803→                discoveries.push((decision.branch_id, DiscoveryMethod::Random));
804→            }
805→        }
806→
807→        if is_new {
808→            let error_intent = classify_error_intent(&exec_result);
809→            new_path_executions.push(ExecutionSummary {
810→                inputs: inputs.clone(),
811→                return_value: exec_result.return_value.clone(),
812→                thrown_error: exec_result
813→                    .thrown_error
814→                    .as_ref()
815→                    .map(|e| format!("{}: {}", e.error_type, e.message)),
816→                lines_executed: exec_result.lines_executed.clone(),
817→                is_new_path: true,
818→                error_intent,
819→            });
820→        }
821→
822→        raw_results.push((inputs, exec_result));
823→    }
824→

823→    }
824→
825→    // --- Per-function teardown ---
826→    if per_function_setup && frontend_supports(&config.capabilities, "teardown") {
827→        send_teardown(frontend, &analysis.name, config.setup_level).await?;
828→    }
829→
830→    let total_lines = instrumentable_line_count
831→        .unwrap_or_else(|| analysis.end_line.saturating_sub(analysis.start_line) + 1);
832→
833→    Ok(ObservationOutput {
834→        function_name: analysis.name.clone(),
835→        iterations,
836→        unique_paths: seen_paths.len(),
837→        lines_covered: all_lines.len(),
838→        total_lines,
839→        new_path_executions,
840→        raw_results,
841→        discoveries,
842→        nondeterministic_fields: vec![],
843→        float_probe_results,
844→    })
845→}
