2018→/// Partition union variants into error and non-error index lists.
2019→fn partition_error_variants(variants: &[TypeInfo]) -> (Vec<usize>, Vec<usize>) {
2020→    let mut error_indices = Vec::new();
2021→    let mut success_indices = Vec::new();
2022→    for (i, v) in variants.iter().enumerate() {
2023→        if matches!(v, TypeInfo::Complex { kind: ComplexKind::Error, .. }) {
2024→            error_indices.push(i);
2025→        } else {
2026→            success_indices.push(i);
2027→        }
2028→    }
2029→    (error_indices, success_indices)
2030→}
