2033→fn category_shaped_value(category: IoCategory, rng: &mut impl Rng) -> Value {
2034→    match category {
2035→        IoCategory::FileSystem => {
2036→            let choice: u8 = rng.random_range(0..3);
2037→            match choice {
2038→                0 => json!(""),
2039→                1 => json!(true),
2040→                _ => Value::Null,
2041→            }
2042→        }
2043→        IoCategory::Network => json!({"status": 200, "data": {}}),
2044→        IoCategory::Database => {
2045→            if rng.random_bool(0.5) {
2046→                json!({"rows": []})
2047→            } else {
2048→                json!({"rowCount": 1})
2049→            }
2050→        }
2051→        IoCategory::PureUtility | IoCategory::ExternalOther => generate_unknown(rng),
2052→    }
2053→}
